class MyHomePage extends StatefulWidget {
  final String title;

  const MyHomePage({
    Key? key,
    required this.title,
  }) : super(key: key);

  @override
  _MyHomePageState createState() => _MyHomePageState();
}

class _MyHomePageState extends State<MyHomePage> with RawKeyboardListenerMixin {
  int _counter = 0;

  void _incrementCounter() {
    setState(() {
      _counter++;
    });
  }

  @override
  bool get enableKeyListener => true;
  bool isKeyDown(Set<LogicalKeyboardKey> keys) {
    return keys.intersection(RawKeyboard.instance.keysPressed).isNotEmpty;
  }

  @override
  void handleKeyDown(RawKeyDownEvent value) {
    if (isKeyDown(
        {LogicalKeyboardKey.controlLeft, LogicalKeyboardKey.controlRight})) {
      //ctrl + q works
      if (value.logicalKey == LogicalKeyboardKey.keyQ) {
        _incrementCounter();
      }
      //ctrl + d does not works
      if (value.logicalKey == LogicalKeyboardKey.keyD) {
        _incrementCounter();
      }
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text(widget.title),
      ),
      body: Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            const Text(
              'Press ctrl + q or ctrl + d to increment the counter\nYou have pushed the button this many times:',
            ),
            Text(
              '$_counter',
              style: Theme.of(context).textTheme.headline4,
            ),
          ],
        ),
      ),
      floatingActionButton: FloatingActionButton(
        onPressed: _incrementCounter,
        tooltip: 'Increment',
        child: const Icon(Icons.add),
      ),
    );
  }
}

mixin RawKeyboardListenerMixin<T extends StatefulWidget> on State<T> {
  // Must be provided by implementing class
  bool get enableKeyListener;

  @override
  void initState() {
    super.initState();
    RawKeyboard.instance.addListener(_handleKey);
  }

  @override
  void dispose() {
    RawKeyboard.instance.removeListener(_handleKey);
    super.dispose();
  }

  void handleKeyUp(RawKeyUpEvent value) {}

  void handleKeyDown(RawKeyDownEvent value) {}

  void _handleKey(RawKeyEvent value) {
    if (enableKeyListener == false) return;
    if (value is RawKeyDownEvent) handleKeyDown(value);
    if (value is RawKeyUpEvent) handleKeyUp(value);
  }
}

```

