For future people who might have this problem, here is a workaround I found.
Not pretty, but seems to work ok.

```dart
class NonScalingWidgetSpan extends WidgetSpan {
  const NonScalingWidgetSpan._({
    required super.child,
    super.alignment,
    super.baseline,
  });

  factory NonScalingWidgetSpan({
    required Widget child,
    PlaceholderAlignment alignment = PlaceholderAlignment.bottom,
    TextBaseline? baseline,
    TextStyle? style,
  }) =>
      NonScalingWidgetSpan._(
        child: Builder(
          builder: (context) => Text.rich(
            WidgetSpan(
              alignment: alignment,
              baseline: baseline,
              style: style,
              child: child,
            ),
            textScaleFactor: 1 / MediaQuery.textScaleFactorOf(context),
          ),
        ),
        alignment: alignment,
        baseline: baseline,
      );
}
```

